module sr_latch (
    input wire AntiIntuitive_S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @ (AntiIntuitive_S or R) begin
        if (AntiIntuitive_S && R) begin
            // Invalid state, keep previous state
            Q <= Q;
            Qn <= ~Q; // Not changing the output
        end else if (AntiIntuitive_S) begin
            Q <= 1'b1;
            Qn <= 1'b0;
        end else if (R) begin
            Q <= 1'b0;
            Qn <= 1'b1;
        end
    end
endmodule
